31	const sumItemPremiums = (items: Item[]): number =>
32	  items.reduce((sum, item) => sum + itemPremium(item), 0);
33	
34	const quoteStep = ({ items }: QuoteStep) => ({
35	  premium: sumItemPremiums(items) + PROCESSING_FEE,
36	});
37	
38	export const processScenario = ({ steps }: Scenario): unknown => ({
39	  results: steps.map(quoteStep),
40	});
